protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // EF Core 9: Default discriminator property renamed from "Discriminator" to "$type".
    // Preserve old name so existing documents remain queryable.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // EF Core 9: id no longer includes discriminator (was "Blog|1", now just "1").
    // Preserve old format so existing documents are still found by FindAsync/point-reads.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // EF Core 9: HasIndex throws for Cosmos entities — removed.
    // Cosmos DB indexing is managed via the container's indexing policy, not EF Core.
}

